  1	import * as React from 'react';
  2	import {
  3	  Button,
  4	  Divider,
  5	  EmptyState,
  6	  EmptyStateBody,
  7	  Menu,
  8	  MenuContent,
  9	  MenuGroup,
 10	  MenuSearch,
 11	  MenuSearchInput,
 12	  MenuItem,
 13	  MenuList,
 14	  TextInput,
 15	  EmptyStateActions,
 16	  EmptyStateHeader,
 17	  EmptyStateFooter,
 18	} from '@patternfly/react-core';
 19	import fuzzysearch from 'fuzzysearch';
 20	import { useTranslation } from 'react-i18next';
 21	import ProjectMenuToggle from './ProjectMenuToggle';
 22	import './ProjectDropdown.scss';
 23	import { alphanumericCompare } from './utils';
 24	import { usePerses } from '../hooks/usePerses';
 25	
 26	export const NoResults: React.FC<{
 27	  onClear: (event: React.MouseEvent<HTMLButtonElement, MouseEvent>) => void;
 28	}> = ({ onClear }) => {
 29	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 30	  return (
 31	    <>
 32	      <Divider />
 33	      <EmptyState>
 34	        <EmptyStateHeader titleText={<>{t('No projects found')}</>} headingLevel="h4" />
 35	        <EmptyStateBody>{t('No results match the filter criteria.')}</EmptyStateBody>
 36	        <EmptyStateFooter>
 37	          <EmptyStateActions>
 38	            <Button
 39	              variant="link"
 40	              onClick={onClear}
 41	              className="monitoring__project-selector__clear-filters"
 42	            >
 43	              {t('Clear filters')}
 44	            </Button>
 45	          </EmptyStateActions>
 46	        </EmptyStateFooter>
 47	      </EmptyState>
 48	    </>
 49	  );
 50	};
 51	
 52	/* ****************************************** */
 53	
 54	export const Filter: React.FC<{
 55	  filterRef: React.Ref<any>;
 56	  onFilterChange: (filterText: string) => void;
 57	  filterText: string;
 58	}> = ({ filterText, filterRef, onFilterChange }) => {
 59	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 60	  return (
 61	    <MenuSearch>
 62	      <MenuSearchInput>
 63	        <TextInput
 64	          data-test="dropdown-text-filter"
 65	          autoFocus
 66	          value={filterText}
 67	          aria-label={t('Select project...')}
 68	          type="search"
 69	          placeholder={t('Select project...')}
 70	          onChange={(_, value: string) => onFilterChange(value)}
 71	          ref={filterRef}
 72	        />
 73	      </MenuSearchInput>
 74	    </MenuSearch>
 75	  );
 76	};
 77	
 78	/* ****************************************** */
 79	
 80	export const ProjectGroup: React.FC<{
 81	  options: { key: string; title: string }[];
 82	  selectedKey: string;
 83	}> = ({ options, selectedKey }) => {
 84	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 85	
 86	  return options.length === 0 ? null : (
 87	    <>
 88	      <Divider />
 89	      <MenuGroup label={t('Projects')}>
 90	        <MenuList>
 91	          {options.map((option) => {
 92	            return (
 93	              <MenuItem
 94	                key={option.key}
 95	                itemId={option.key}
 96	                isSelected={selectedKey === option.key}
 97	                data-test="dropdown-menu-item-link"
 98	              >
 99	                {option.title}
100	              </MenuItem>
101	            );
102	          })}
103	        </MenuList>
104	      </MenuGroup>
105	    </>
106	  );
107	};
108	
109	/* ****************************************** */
110	
111	const ProjectMenu: React.FC<{
112	  setOpen: (isOpen: boolean) => void;
113	  onSelect: (event: React.MouseEvent, itemId: string) => void;
114	  selected?: string;
115	  menuRef: React.MutableRefObject<HTMLDivElement>;
116	}> = ({ setOpen, onSelect, selected, menuRef }) => {
117	  const filterRef = React.useRef(null);
118	
119	  const [filterText, setFilterText] = React.useState('');
120	
121	  const { persesProjects } = usePerses();
122	
123	  const optionItems = React.useMemo(() => {
124	    const items = persesProjects.map((item) => {
125	      const { name } = item.metadata;
126	      return { title: item?.spec?.display?.name ?? name, key: name };
127	    });
128	
129	    if (!items.some((option) => option.key === selected)) {
130	      items.push({ title: selected, key: selected }); // Add current project if it isn't included
131	    }
132	    items.sort((a, b) => alphanumericCompare(a.title, b.title));
133	
134	    return items;
135	  }, [persesProjects, selected]);
136	
137	  const isOptionShown = React.useCallback(
138	    (option) => {
139	      return fuzzysearch(filterText.toLowerCase(), option.title.toLowerCase());
140	    },
141	    [filterText],
142	  );
143	
144	  const { filteredOptions } = React.useMemo(
145	    () =>
146	      optionItems.reduce(
147	        (filtered, option) => {
148	          if (isOptionShown(option)) {
149	            filtered.filteredOptions.push(option);
150	          }
151	          return filtered;
152	        },
153	        { filteredOptions: [] },
154	      ),
155	    [isOptionShown, optionItems],
156	  );
157	
158	  return (
159	    <Menu
160	      className="monitoring__project-dropdown__menu"
161	      ref={menuRef}
162	      onSelect={(event: React.MouseEvent, itemId: string) => {
163	        setOpen(false);
164	        onSelect(event, itemId);
165	      }}
166	      activeItemId={selected}
167	      data-test="project-dropdown-menu"
168	      isScrollable
169	    >
170	      <MenuContent maxMenuHeight="60vh">
171	        <Filter filterRef={filterRef} onFilterChange={setFilterText} filterText={filterText} />
172	        {filteredOptions.length === 0 ? (
173	          <NoResults
174	            onClear={(event) => {
175	              event.preventDefault();
176	              event.stopPropagation();
177	              setFilterText('');
178	              filterRef.current?.focus();
179	            }}
180	          />
181	        ) : null}
182	        <ProjectGroup options={filteredOptions} selectedKey={selected} />
183	      </MenuContent>
184	    </Menu>
185	  );
186	};
187	
188	/* ****************************************** */
189	
190	const ProjectDropdown: React.FC<ProjectDropdownProps> = ({
191	  disabled,
192	  onSelect,
193	  selected,
194	  shortCut,
195	}) => {
196	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
197	  const menuRef = React.useRef(null);
198	  const [isOpen, setOpen] = React.useState(false);
199	  const { persesProjectsError, persesProjectsLoading, persesProjects } = usePerses();
200	
201	  // const title = selected === LEGACY_DASHBOARDS_KEY ? legacyDashboardsTitle : selected;
202	
203	  const menuProps = {
204	    setOpen,
205	    onSelect,
206	    selected,
207	    menuRef,
208	  };
209	
210	  if (persesProjectsLoading || persesProjectsError || persesProjects.length === 0) {
211	    return null;
212	  }
213	
214	  const selectedProject = persesProjects.find(
215	    (persesProject) => persesProject.metadata.name === selected,
216	  );
217	  const title = selectedProject?.spec?.display?.name ?? t('Dashboards');
218	
219	  return (
220	    <div className="monitoring__project-dropdown">
221	      <ProjectMenuToggle
222	        disabled={disabled}
223	        menu={<ProjectMenu {...menuProps} />}
224	        menuRef={menuRef}
225	        isOpen={isOpen}
226	        title={`${t('Project')}: ${title}`}
227	        onToggle={(menuState) => {
228	          setOpen(menuState);
229	        }}
230	        shortCut={shortCut}
231	      />
232	    </div>
233	  );
234	};
235	
236	type ProjectDropdownProps = {
237	  disabled?: boolean;
238	  onSelect?: (event: React.MouseEvent | React.ChangeEvent, value: string) => void;
239	  shortCut?: string;
240	  selected?: string;
241	};
242	
243	export default ProjectDropdown;

